@startuml

class Dummy {
  -private
  #protected
  ~pkg method()
  +public()
}

interface User <<interface>> {
  #createAccount(AccountType)
  #login()
  #logout()
}

class Admin {
  #createService()
  #removeAccount()
  #removeAccount()
  #setHourlyRate()
  #setForm(Service.type, customerInfo)
}

class Employee {
  #createAccount(Employee)
  #selectService()
  #setBusinessHour()
  #boolean processServiceRequest()
  #notifyCustomer()
}

class Customer {
  #createAccount(Customer)
  #searchBranch()
  #selectService()
  #getForm(Service.type).fill()
  #submitForm()
  #rateBranch()
}

interface Form <<interface>> {
  #firstName
  #lastName
  #dateOfBirth
  #address
  #email
}

abstract class RentalForm <<abstract>> {
  #pickupTime
  #returnTime
  #licenseType
}

class MovingForm {
  #startLocation
  #endLocation
  #numberOfMovers
  #numberOfBoxes
}

class carRentalForm {
  #carType
}

class truckRentalForm {
  #usageArea
}

Admin --|> User
Employee --|> User
Customer --|> User

RentalForm --|> Form
MovingForm --|> Form

carRentalForm --|> RentalForm
truckRentalForm --|> RentalForm

@enduml
